{"name": "ingest_webhook", "kind": "normal", "description": "处理外部 webhook POST 请求，验证 HMAC 签名后落库存储", "code": "import json
import hmac
import hashlib
import time
from datetime import datetime, timezone

# 可配置项：签名密钥（建议从环境变量或安全存储读取）
SECRET_KEY = "your-webhook-secret-key"  # 生产环境应替换为安全来源

# 模拟落库存储（可替换为真实 DB 连接，如 Supabase / SQLite）
_webhook_store = []

def verify_signature(body: str, signature_header: str, secret: str) -> bool:
    """HMAC-SHA256 签名验证"""
    expected_sig = hmac.new(
        secret.encode("utf-8"),
        body.encode("utf-8"),
        hashlib.sha256
    ).hexdigest()
    return hmac.compare_digest(expected_sig, signature_header)

def store_event(event_data: dict) -> dict:
    """将已验证的事件数据落库"""
    record = {
        "id": f"evt_{int(time.time() * 1000)}_{len(_webhook_store)}",
        "received_at": datetime.now(timezone.utc).isoformat(),
        "payload": event_data,
        "status": "stored",
    }
    _webhook_store.append(record)
    return record

def run(
    body: str | dict,
    signature: str = "",
    signature_header: str = "",
    timestamp: str = "",
    secret: str = SECRET_KEY,
    tolerance_seconds: int = 300,
):
    """
    处理 webhook POST 请求

    参数:
        body: 请求体（原始字符串 或 已解析的 dict）
        signature: 签名值（直接提供）
        signature_header: 从请求头提取的签名字段（如 X-Hub-Signature-256）
        timestamp: 请求时间戳（可选，用于防止重放攻击）
        secret: 签名密钥
        tolerance_seconds: 时间戳容忍窗口（秒）

    返回:
        dict: { "success": bool, "event_id": str|None, "error": str|None }
    """
    # 1. 统一处理 body
    if isinstance(body, dict):
        body_str = json.dumps(body, separators=(",", ":"), sort_keys=True)
        body_dict = body
    elif isinstance(body, str):
        body_str = body
        try:
            body_dict = json.loads(body)
        except json.JSONDecodeError:
            body_dict = {"raw": body}
    else:
        return {"success": False, "event_id": None, "error": "Invalid body type"}

    # 2. 取签名（优先用 signature 参数，否则用 signature_header）
    sig = signature or signature_header

    # 3. 可选：防重放攻击 —— 校验时间戳
    if timestamp:
        try:
            ts = int(timestamp)
            now = int(time.time())
            if abs(now - ts) > tolerance_seconds:
                return {
                    "success": False,
                    "event_id": None,
                    "error": f"Timestamp out of tolerance window ({tolerance_seconds}s)",
                }
        except ValueError:
            return {"success": False, "event_id": None, "error": "Invalid timestamp format"}

    # 4. 验证签名
    if not sig:
        return {"success": False, "event_id": None, "error": "Missing signature"}

    if not verify_signature(body_str, sig, secret):
        return {"success": False, "event_id": None, "error": "Signature verification failed"}

    # 5. 落库
    record = store_event(body_dict)

    return {
        "success": True,
        "event_id": record["id"],
        "received_at": record["received_at"],
        "error": None,
    }
"}
